text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트가 통과하는 경우 금요일 15:00 KST를 공개 릴리스 목표로 한다.",
        "certainty": "confirmed"
      },
      {
        "topic": "packageName mismatch 대응",
        "decision": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다.",
        "certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경한다.",
        "result": "rejected"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스 제안은 내부 스트레치 목표일 뿐이며 확정 일정이 아니다.",
        "certainty": "not_committed"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 절차는 가능하면 목요일까지 검토 필요 의견이 있었으나, 담당자 배정은 확정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로는 릴리스를 지연시킬 수 있다."
      },
      {
        "risk": "README 설치 절차가 오래되었거나 부정확하면 릴리스 노트가 사용자에게 오해를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 금요일 10:00 KST까지 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": null,
      "task": "README 설치 절차를 목요일까지 가능하면 검토한다.",
      "due": "목요일 가능 시",
      "status": "proposed_without_owner",
      "source_certainty": "explicit"
    }
  ],
  "followup_note": {
    "check_next": [
      "Minjun의 스모크 테스트 통과 여부를 먼저 확인한다.",
      "스모크 결과 공유 이후 Hara의 tarball 경로 점검 결과를 확인한다.",
      "Doyun의 failure triage note 작성 완료 여부를 확인한다.",
      "README 설치 절차 검토의 담당자 지정 여부를 확인한다.",
      "최종 릴리스 승인 권한자에 대한 답변을 확보한다.",
      "릴리스 노트에 내부 수요일 스트레치 목표를 포함할지 결정 여부를 확인한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "미지정 담당자",
      "명시되지 않은 추가 마감일",
      "수요일 릴리스를 확정 일정으로 해석하는 내용"
    ]
  },
  "non_invention_rules": [
    "인라인 합성 회의 기록에 없는 고객, 예산, 보안, 장애, 법무 사실을 추가하지 않는다.",
    "확정 결정과 제안, 반려안, 내부 스트레치 목표, 리스크, 열린 질문을 섞지 않는다.",
    "담당자나 마감이 명시되지 않은 항목은 추정하지 않는다.",
    "수요일 제안은 내부 스트레치 목표로만 기록하고 확정 릴리스 일정으로 승격하지 않는다.",
    "반려된 제안은 실행 항목이나 확정 방침처럼 쓰지 않는다."
  ]
}
